    {"question_text": "What is the output of this Chain of Responsibility implementation?\n\nclass Handler:\n    def __init__(self, successor=None):\n        self._successor = successor\n    def handle(self, request):\n        if self._successor:\n            return self._successor.handle(request)\n        return None\n\nclass AuthHandler(Handler):\n    def handle(self, request):\n        if not request.get('token'):\n            return 'auth_failed'\n        return super().handle(request)\n\nclass ValidationHandler(Handler):\n    def handle(self, request):\n        if not request.get('data'):\n            return 'validation_failed'\n        return super().handle(request)\n\nclass ProcessHandler(Handler):\n    def handle(self, request):\n        return f'processed: {request[\"data\"]}'\n\nchain = AuthHandler(ValidationHandler(ProcessHandler()))\nprint(chain.handle({'token': 'abc', 'data': 'hello'}))", "option_a": "processed: hello", "option_b": "auth_failed", "option_c": "validation_failed", "option_d": "None", "correct_answer": "A", "difficulty": "advanced", "topic": "design_patterns"},
    {"question_text": "In the Mediator pattern for agent systems, what problem does it solve?", "option_a": "It reduces coupling between components by having them communicate through a central mediator instead of directly with each other", "option_b": "It speeds up communication between agents", "option_c": "It eliminates the need for message passing", "option_d": "It creates direct connections between all agents", "correct_answer": "A", "difficulty": "advanced", "topic": "design_patterns"},
    {"question_text": "What is the output of this Abstract Factory pattern?\n\nclass Button:\n    def render(self): pass\n\nclass DarkButton(Button):\n    def render(self): return 'dark_button'\n\nclass LightButton(Button):\n    def render(self): return 'light_button'\n\nclass ThemeFactory:\n    @staticmethod\n    def create(theme):\n        factories = {'dark': DarkButton, 'light': LightButton}\n        return factories[theme]()\n\nbutton = ThemeFactory.create('dark')\nprint(button.render())", "option_a": "dark_button", "option_b": "light_button", "option_c": "Button", "option_d": "None", "correct_answer": "A", "difficulty": "advanced", "topic": "design_patterns"},
    {"question_text": "What is the Prototype pattern and when would you use it in agent development?", "option_a": "It creates new objects by cloning existing ones, useful when object creation is expensive and you need variations of a configured template", "option_b": "It defines the first version of a class before refactoring", "option_c": "It creates a base class that all agents must inherit", "option_d": "It is used exclusively for testing with mock objects", "correct_answer": "A", "difficulty": "advanced", "topic": "design_patterns"},
    {"question_text": "What is the output of this Decorator pattern (GoF, not Python decorator) implementation?\n\nclass TextComponent:\n    def render(self): return 'Hello'\n\nclass BoldDecorator:\n    def __init__(self, component):\n        self._component = component\n    def render(self): return f'<b>{self._component.render()}</b>'\n\nclass ItalicDecorator:\n    def __init__(self, component):\n        self._component = component\n    def render(self): return f'<i>{self._component.render()}</i>'\n\ntext = ItalicDecorator(BoldDecorator(TextComponent()))\nprint(text.render())", "option_a": "<i><b>Hello</b></i>", "option_b": "<b><i>Hello</i></b>", "option_c": "<b>Hello</b>", "option_d": "Hello", "correct_answer": "A", "difficulty": "advanced", "topic": "design_patterns"},
    {"question_text": "Which SOLID principle does the following code violate?\n\nclass ReportGenerator:\n    def generate_report(self, data):\n        report = self._format_data(data)\n        self._save_to_file(report)\n        self._send_email(report)\n        self._log_generation(report)\n        return report", "option_a": "Single Responsibility Principle - the class handles formatting, persistence, notification, and logging", "option_b": "Open/Closed Principle", "option_c": "Liskov Substitution Principle", "option_d": "Interface Segregation Principle", "correct_answer": "A", "difficulty": "advanced", "topic": "design_patterns"},
    {"question_text": "What is the output of this Strategy pattern for selecting AI model providers?\n\nclass ModelStrategy:\n    def generate(self, prompt): pass\n\nclass OpenAIStrategy(ModelStrategy):\n    def generate(self, prompt):\n        return f'openai: {prompt}'\n\nclass AnthropicStrategy(ModelStrategy):\n    def generate(self, prompt):\n        return f'anthropic: {prompt}'\n\nclass Agent:\n    def __init__(self, strategy):\n        self._strategy = strategy\n    def think(self, prompt):\n        return self._strategy.generate(prompt)\n    def set_strategy(self, strategy):\n        self._strategy = strategy\n\nagent = Agent(OpenAIStrategy())\nresult1 = agent.think('hello')\nagent.set_strategy(AnthropicStrategy())\nresult2 = agent.think('hello')\nprint(result1, '|', result2)", "option_a": "openai: hello | anthropic: hello", "option_b": "openai: hello | openai: hello", "option_c": "anthropic: hello | anthropic: hello", "option_d": "hello | hello", "correct_answer": "A", "difficulty": "advanced", "topic": "design_patterns"},
    {"question_text": "What is the primary benefit of using Dependency Injection in agent systems for testing?", "option_a": "It allows replacing real dependencies (API clients, databases) with mock objects without changing the agent's code", "option_b": "It makes tests run faster", "option_c": "It eliminates the need for unit tests", "option_d": "It automatically generates test cases", "correct_answer": "A", "difficulty": "advanced", "topic": "design_patterns"},

    {"question_text": "What is the output of this Template Method pattern for processing agent tasks?\n\nfrom abc import ABC, abstractmethod\n\nclass TaskProcessor(ABC):\n    def process(self, task):\n        validated = self.validate(task)\n        transformed = self.transform(validated)\n        return self.execute(transformed)\n    \n    @abstractmethod\n    def validate(self, task): pass\n    @abstractmethod\n    def transform(self, task): pass\n    @abstractmethod\n    def execute(self, task): pass\n\nclass UpperCaseProcessor(TaskProcessor):\n    def validate(self, task): return task.strip()\n    def transform(self, task): return task.upper()\n    def execute(self, task): return f'Done: {task}'\n\nresult = UpperCaseProcessor().process('  hello  ')\nprint(result)", "option_a": "Done: HELLO", "option_b": "Done:   hello  ", "option_c": "HELLO", "option_d": "Done: hello", "correct_answer": "A", "difficulty": "advanced", "topic": "design_patterns"},
    {"question_text": "In the Repository pattern, what is the difference between a Repository and a DAO (Data Access Object)?", "option_a": "Repository works with domain objects and encapsulates query logic; DAO is a lower-level abstraction closer to the database table structure", "option_b": "They are identical concepts", "option_c": "DAO is newer and replaces Repository", "option_d": "Repository handles caching; DAO handles queries", "correct_answer": "A", "difficulty": "advanced", "topic": "design_patterns"},
    {"question_text": "What is the output of this Observer pattern with event filtering?\n\nclass FilteredEventBus:\n    def __init__(self):\n        self._handlers = []\n    \n    def subscribe(self, event_filter, handler):\n        self._handlers.append((event_filter, handler))\n    \n    def emit(self, event):\n        results = []\n        for filter_fn, handler in self._handlers:\n            if filter_fn(event):\n                results.append(handler(event))\n        return results\n\nbus = FilteredEventBus()\nbus.subscribe(lambda e: e['type'] == 'error', lambda e: f'ERROR: {e[\"msg\"]}')\nbus.subscribe(lambda e: True, lambda e: f'LOG: {e[\"msg\"]}')\n\nresult = bus.emit({'type': 'error', 'msg': 'fail'})\nprint(len(result))", "option_a": "2", "option_b": "1", "option_c": "0", "option_d": "3", "correct_answer": "A", "difficulty": "advanced", "topic": "design_patterns"},
    {"question_text": "What does the Liskov Substitution Principle state in the context of Python class hierarchies?", "option_a": "Subclasses should be substitutable for their base classes without altering program correctness", "option_b": "Classes should only inherit from abstract base classes", "option_c": "Substitution should only happen at runtime", "option_d": "Parent classes should be substitutable for child classes", "correct_answer": "A", "difficulty": "advanced", "topic": "design_patterns"},
    {"question_text": "What is the output of this Builder pattern with validation?\n\nclass QueryBuilder:\n    def __init__(self):\n        self._select = []\n        self._where = []\n        self._limit = None\n    \n    def select(self, *fields):\n        self._select.extend(fields)\n        return self\n    \n    def where(self, condition):\n        self._where.append(condition)\n        return self\n    \n    def limit(self, n):\n        self._limit = n\n        return self\n    \n    def build(self):\n        parts = [f'SELECT {\", \".join(self._select)}']\n        if self._where:\n            parts.append(f'WHERE {\", \".join(self._where)}')\n        if self._limit:\n            parts.append(f'LIMIT {self._limit}')\n        return ' '.join(parts)\n\nquery = QueryBuilder().select('name', 'age').where('age > 18').limit(10).build()\nprint(query)", "option_a": "SELECT name, age WHERE age > 18 LIMIT 10", "option_b": "SELECT * WHERE age > 18", "option_c": "name, age WHERE age > 18 LIMIT 10", "option_d": "SELECT name, age", "correct_answer": "A", "difficulty": "advanced", "topic": "design_patterns"},
    {"question_text": "Which design pattern is best suited for implementing an AI agent that can switch between different reasoning modes (analytical, creative, summarization)?", "option_a": "Strategy pattern - encapsulate each reasoning mode as an interchangeable strategy", "option_b": "Singleton pattern", "option_c": "Factory pattern", "option_d": "Observer pattern", "correct_answer": "A", "difficulty": "advanced", "topic": "design_patterns"},
    {"question_text": "What is the output of this Proxy pattern for lazy loading?\n\nclass HeavyResource:\n    def __init__(self):\n        self.data = 'loaded'\n    def get_data(self):\n        return self.data\n\nclass LazyProxy:\n    def __init__(self):\n        self._resource = None\n    def get_data(self):\n        if self._resource is None:\n            self._resource = HeavyResource()\n        return self._resource.get_data()\n\nproxy = LazyProxy()\nprint(proxy._resource is None)\nresult = proxy.get_data()\nprint(proxy._resource is None, result)", "option_a": "True\\nFalse loaded", "option_b": "False\\nFalse loaded", "option_c": "True\\nTrue loaded", "option_d": "True\\nFalse None", "correct_answer": "A", "difficulty": "advanced", "topic": "design_patterns"},
    {"question_text": "What is the correct implementation of the Singleton pattern using a metaclass?\n\nclass SingletonMeta(type):\n    _instances = {}\n    def __call__(cls, *args, **kwargs):\n        if cls not in cls._instances:\n            cls._instances[cls] = super().__call__(*args, **kwargs)\n        return cls._instances[cls]\n\nclass Database(metaclass=SingletonMeta):\n    def __init__(self):\n        self.connection = 'connected'\n\na = Database()\nb = Database()\nprint(a is b)", "option_a": "True", "option_b": "False", "option_c": "TypeError", "option_d": "None", "correct_answer": "A", "difficulty": "advanced", "topic": "design_patterns"},

    {"question_text": "What is the output of this Composite pattern for building agent tool chains?\n\nclass Tool:\n    def execute(self, input_data): pass\n\nclass SimpleTool(Tool):\n    def __init__(self, name, func):\n        self.name = name\n        self.func = func\n    def execute(self, input_data):\n        return self.func(input_data)\n\nclass ToolChain(Tool):\n    def __init__(self):\n        self._tools = []\n    def add(self, tool):\n        self._tools.append(tool)\n        return self\n    def execute(self, input_data):\n        result = input_data\n        for tool in self._tools:\n            result = tool.execute(result)\n        return result\n\nchain = ToolChain()\nchain.add(SimpleTool('upper', str.upper))\nchain.add(SimpleTool('reverse', lambda s: s[::-1]))\nprint(chain.execute('hello'))", "option_a": "OLLEH", "option_b": "olleh", "option_c": "HELLO", "option_d": "hello", "correct_answer": "A", "difficulty": "advanced", "topic": "design_patterns"},
    {"question_text": "What violates the Interface Segregation Principle in this code?\n\nclass Worker:\n    def work(self): pass\n    def eat(self): pass\n    def sleep(self): pass\n\nclass Robot(Worker):\n    def work(self): return 'working'\n    def eat(self): raise NotImplementedError  # Robots don't eat\n    def sleep(self): raise NotImplementedError  # Robots don't sleep", "option_a": "Robot is forced to implement methods (eat, sleep) it doesn't need - the interface should be split into smaller focused interfaces", "option_b": "Worker has too few methods", "option_c": "Robot should inherit from multiple classes", "option_d": "The methods should be static", "correct_answer": "A", "difficulty": "advanced", "topic": "design_patterns"},
    {"question_text": "In the context of agent development, what pattern does this code implement?\n\nclass ToolRegistry:\n    _tools = {}\n    \n    @classmethod\n    def register(cls, name):\n        def decorator(tool_class):\n            cls._tools[name] = tool_class\n            return tool_class\n        return decorator\n    \n    @classmethod\n    def create(cls, name, *args, **kwargs):\n        if name not in cls._tools:\n            raise ValueError(f'Unknown tool: {name}')\n        return cls._tools[name](*args, **kwargs)\n\n@ToolRegistry.register('search')\nclass SearchTool:\n    def run(self, query): return f'results for: {query}'", "option_a": "Registry pattern combined with Factory - tools self-register via decorator and are created by name", "option_b": "Pure Singleton pattern", "option_c": "Observer pattern", "option_d": "Strategy pattern only", "correct_answer": "A", "difficulty": "advanced", "topic": "design_patterns"},
    {"question_text": "What is the output of this implementation of the Null Object pattern?\n\nclass Logger:\n    def log(self, msg): print(msg)\n\nclass NullLogger:\n    def log(self, msg): pass  # intentionally does nothing\n\ndef process(data, logger=None):\n    logger = logger or NullLogger()\n    logger.log(f'Processing: {data}')\n    return data.upper()\n\nresult = process('hello')\nprint(result)", "option_a": "HELLO", "option_b": "Processing: hello\\nHELLO", "option_c": "None", "option_d": "hello", "correct_answer": "A", "difficulty": "advanced", "topic": "design_patterns"},
    {"question_text": "What is the output?\n\nclass Middleware:\n    def __init__(self, next_handler=None):\n        self.next = next_handler\n    def handle(self, request):\n        request = self.process(request)\n        if self.next:\n            return self.next.handle(request)\n        return request\n    def process(self, request):\n        return request\n\nclass AuthMiddleware(Middleware):\n    def process(self, request):\n        request['authenticated'] = True\n        return request\n\nclass LogMiddleware(Middleware):\n    def process(self, request):\n        request['logged'] = True\n        return request\n\npipeline = LogMiddleware(AuthMiddleware())\nresult = pipeline.handle({'data': 'test'})\nprint(sorted(result.keys()))", "option_a": "['authenticated', 'data', 'logged']", "option_b": "['data', 'logged']", "option_c": "['authenticated', 'data']", "option_d": "['data']", "correct_answer": "A", "difficulty": "advanced", "topic": "design_patterns"},
    {"question_text": "Which pattern correctly implements a plugin system for an AI agent?\n\nclass PluginBase:\n    plugins = []\n    def __init_subclass__(cls, **kwargs):\n        super().__init_subclass__(**kwargs)\n        cls.plugins.append(cls)\n\nclass SearchPlugin(PluginBase):\n    name = 'search'\n    def execute(self, query): return f'search: {query}'\n\nclass CalcPlugin(PluginBase):\n    name = 'calc'\n    def execute(self, expr): return f'calc: {expr}'\n\nprint(len(PluginBase.plugins))", "option_a": "2", "option_b": "0", "option_c": "3", "option_d": "1", "correct_answer": "A", "difficulty": "advanced", "topic": "design_patterns"},
    {"question_text": "What design pattern does Python's logging module use for its handlers?\n\nlogger = logging.getLogger('app')\nlogger.addHandler(StreamHandler())\nlogger.addHandler(FileHandler('app.log'))\nlogger.addHandler(SMTPHandler(...))", "option_a": "Observer/Publisher-Subscriber pattern - the logger publishes log records to all registered handlers", "option_b": "Singleton pattern only", "option_c": "Factory pattern", "option_d": "Command pattern", "correct_answer": "A", "difficulty": "advanced", "topic": "design_patterns"},
    {"question_text": "What is the output of this implementation using the Specification pattern for filtering?\n\nclass Specification:\n    def is_satisfied_by(self, item): pass\n    def __and__(self, other):\n        return AndSpec(self, other)\n    def __or__(self, other):\n        return OrSpec(self, other)\n\nclass AndSpec(Specification):\n    def __init__(self, *specs):\n        self.specs = specs\n    def is_satisfied_by(self, item):\n        return all(s.is_satisfied_by(item) for s in self.specs)\n\nclass OrSpec(Specification):\n    def __init__(self, *specs):\n        self.specs = specs\n    def is_satisfied_by(self, item):\n        return any(s.is_satisfied_by(item) for s in self.specs)\n\nclass MinAge(Specification):\n    def __init__(self, age): self.age = age\n    def is_satisfied_by(self, item): return item['age'] >= self.age\n\nclass HasRole(Specification):\n    def __init__(self, role): self.role = role\n    def is_satisfied_by(self, item): return item.get('role') == self.role\n\nspec = MinAge(18) & HasRole('admin')\nuser = {'age': 25, 'role': 'admin'}\nprint(spec.is_satisfied_by(user))", "option_a": "True", "option_b": "False", "option_c": "None", "option_d": "TypeError", "correct_answer": "A", "difficulty": "advanced", "topic": "design_patterns"},

    {"question_text": "What is the correct implementation of the Unit of Work pattern for managing database transactions in agent systems?", "option_a": "Track all changes (inserts, updates, deletes) and commit them as a single atomic transaction", "option_b": "Commit after every single operation", "option_c": "Never commit - use autocommit mode", "option_d": "Use multiple transactions for each entity type", "correct_answer": "A", "difficulty": "advanced", "topic": "design_patterns"},
    {"question_text": "What is the output of this Flyweight pattern implementation for sharing common agent configurations?\n\nclass ModelConfig:\n    _configs = {}\n    \n    def __new__(cls, model_name, temperature=0.7):\n        key = (model_name, temperature)\n        if key not in cls._configs:\n            instance = super().__new__(cls)\n            instance.model_name = model_name\n            instance.temperature = temperature\n            cls._configs[key] = instance\n        return cls._configs[key]\n\na = ModelConfig('gpt-4', 0.7)\nb = ModelConfig('gpt-4', 0.7)\nc = ModelConfig('gpt-4', 0.9)\nprint(a is b, a is c)", "option_a": "True False", "option_b": "True True", "option_c": "False False", "option_d": "False True", "correct_answer": "A", "difficulty": "advanced", "topic": "design_patterns"},
    {"question_text": "What is the key benefit of the Dependency Inversion Principle (the D in SOLID)?", "option_a": "High-level modules should depend on abstractions, not concrete implementations - this makes the system more flexible and testable", "option_b": "Dependencies should be injected from the top down", "option_c": "All dependencies should be inverted (reversed)", "option_d": "Low-level modules should control high-level modules", "correct_answer": "A", "difficulty": "advanced", "topic": "design_patterns"},
    {"question_text": "What pattern does this code implement for handling agent tool selection?\n\nclass ToolSelector:\n    def __init__(self):\n        self._handlers = []\n    \n    def register(self, condition, tool):\n        self._handlers.append((condition, tool))\n    \n    def select(self, query):\n        for condition, tool in self._handlers:\n            if condition(query):\n                return tool\n        return None\n\nselector = ToolSelector()\nselector.register(lambda q: 'search' in q, 'web_search')\nselector.register(lambda q: 'calculate' in q, 'calculator')\nselector.register(lambda q: True, 'general')\nprint(selector.select('please search for Python'))", "option_a": "web_search", "option_b": "general", "option_c": "calculator", "option_d": "None", "correct_answer": "A", "difficulty": "advanced", "topic": "design_patterns"},
    {"question_text": "What is the output of this implementation of the Memento pattern for agent state management?\n\nclass AgentState:\n    def __init__(self):\n        self.history = []\n        self.context = ''\n    \n    def save(self):\n        return {'history': self.history.copy(), 'context': self.context}\n    \n    def restore(self, memento):\n        self.history = memento['history']\n        self.context = memento['context']\n\nstate = AgentState()\nstate.history.append('msg1')\nstate.context = 'topic_a'\nsnapshot = state.save()\n\nstate.history.append('msg2')\nstate.context = 'topic_b'\nstate.restore(snapshot)\nprint(len(state.history), state.context)", "option_a": "1 topic_a", "option_b": "2 topic_b", "option_c": "0 topic_a", "option_d": "1 topic_b", "correct_answer": "A", "difficulty": "advanced", "topic": "design_patterns"},
    {"question_text": "Which design pattern is most appropriate for implementing a conversation agent that needs to handle different message types (text, image, audio) with different processing logic?", "option_a": "Visitor pattern - separates the algorithm from the object structure, allowing new operations without modifying message classes", "option_b": "Singleton pattern", "option_c": "Builder pattern", "option_d": "Prototype pattern", "correct_answer": "A", "difficulty": "advanced", "topic": "design_patterns"},
    {"question_text": "What is the output of this Facade pattern implementation?\n\nclass SubsystemA:\n    def operation(self): return 'A'\n\nclass SubsystemB:\n    def operation(self): return 'B'\n\nclass SubsystemC:\n    def operation(self): return 'C'\n\nclass AgentFacade:\n    def __init__(self):\n        self._a = SubsystemA()\n        self._b = SubsystemB()\n        self._c = SubsystemC()\n    \n    def complex_operation(self):\n        results = []\n        results.append(self._a.operation())\n        results.append(self._b.operation())\n        results.append(self._c.operation())\n        return '+'.join(results)\n\nfacade = AgentFacade()\nprint(facade.complex_operation())", "option_a": "A+B+C", "option_b": "ABC", "option_c": "A B C", "option_d": "C+B+A", "correct_answer": "A", "difficulty": "advanced", "topic": "design_patterns"},
    {"question_text": "What problem does the Open/Closed Principle solve in this context?\n\n# Before (violates OCP)\nclass Formatter:\n    def format(self, data, format_type):\n        if format_type == 'json': return json.dumps(data)\n        elif format_type == 'xml': return to_xml(data)\n        elif format_type == 'csv': return to_csv(data)\n\n# After (follows OCP)\nclass Formatter(ABC):\n    @abstractmethod\n    def format(self, data): pass\n\nclass JSONFormatter(Formatter):\n    def format(self, data): return json.dumps(data)", "option_a": "The class is open for extension (new formatters) but closed for modification (existing code doesn't change)", "option_b": "The class becomes faster", "option_c": "The class uses less memory", "option_d": "The class becomes thread-safe", "correct_answer": "A", "difficulty": "advanced", "topic": "design_patterns"},

    {"question_text": "In Python, which is the most Pythonic way to implement the Strategy pattern?", "option_a": "Create abstract base classes with concrete strategy classes", "option_b": "Pass callable functions directly - functions are first-class objects in Python, making full class hierarchies unnecessary for simple strategies", "option_c": "Use if/elif chains to select behavior", "option_d": "Use metaclasses", "correct_answer": "B", "difficulty": "advanced", "topic": "design_patterns"},
