    {"question_text": "What is the output of this implementation of the Iterator pattern with custom traversal?\n\nclass TreeNode:\n    def __init__(self, value, children=None):\n        self.value = value\n        self.children = children or []\n\nclass BFSIterator:\n    def __init__(self, root):\n        self._queue = [root] if root else []\n    def __iter__(self):\n        return self\n    def __next__(self):\n        if not self._queue:\n            raise StopIteration\n        node = self._queue.pop(0)\n        self._queue.extend(node.children)\n        return node.value\n\ntree = TreeNode(1, [TreeNode(2, [TreeNode(4)]), TreeNode(3, [TreeNode(5)])])\nresult = list(BFSIterator(tree))\nprint(result)", "option_a": "[1, 4, 5, 2, 3]", "option_b": "[1, 2, 3, 4, 5]", "option_c": "[4, 2, 5, 3, 1]", "option_d": "[1, 2, 4, 3, 5]", "correct_answer": "B", "difficulty": "advanced", "topic": "design_patterns"},
