    {"question_text": "What is the output?\n\nclass Subject:\n    def __init__(self):\n        self._observers = []\n        self._state = None\n    \n    def attach(self, observer):\n        self._observers.append(observer)\n    \n    @property\n    def state(self):\n        return self._state\n    \n    @state.setter\n    def state(self, value):\n        self._state = value\n        self._notify()\n    \n    def _notify(self):\n        for obs in self._observers:\n            obs.update(self._state)\n\nclass Observer:\n    def __init__(self, name):\n        self.name = name\n        self.received = []\n    def update(self, state):\n        self.received.append(state)\n\nsubject = Subject()\nobs1 = Observer('A')\nobs2 = Observer('B')\nsubject.attach(obs1)\nsubject.attach(obs2)\nsubject.state = 'hello'\nsubject.state = 'world'\nprint(len(obs1.received), obs2.received[-1])", "option_a": "1 hello", "option_b": "2 world", "option_c": "2 hello", "option_d": "1 world", "correct_answer": "B", "difficulty": "advanced", "topic": "design_patterns"},
