    {"question_text": "What is the output of this Object Pool pattern implementation?\n\nclass ConnectionPool:\n    def __init__(self, size):\n        self._pool = [f'conn_{i}' for i in range(size)]\n        self._in_use = set()\n    \n    def acquire(self):\n        if not self._pool:\n            raise RuntimeError('Pool exhausted')\n        conn = self._pool.pop()\n        self._in_use.add(conn)\n        return conn\n    \n    def release(self, conn):\n        self._in_use.discard(conn)\n        self._pool.append(conn)\n\npool = ConnectionPool(3)\nc1 = pool.acquire()\nc2 = pool.acquire()\npool.release(c1)\nc3 = pool.acquire()\nprint(c1 == c3, len(pool._pool))", "option_a": "False 0", "option_b": "True 0", "option_c": "True 1", "option_d": "False 1", "correct_answer": "B", "difficulty": "advanced", "topic": "design_patterns"},
    {"question_text": "What is the output?\n\nclass EventDrivenAgent:\n    def __init__(self):\n        self._handlers = {}\n        self._log = []\n    \n    def on(self, event):\n        def decorator(func):\n            self._handlers.setdefault(event, []).append(func)\n            return func\n        return decorator\n    \n    def emit(self, event, *args):\n        for handler in self._handlers.get(event, []):\n            result = handler(*args)\n            self._log.append(result)\n\nagent = EventDrivenAgent()\n\n@agent.on('input')\ndef process_input(text):\n    return text.upper()\n\n@agent.on('input')\ndef log_input(text):\n    return f'logged: {text}'\n\nagent.emit('input', 'hello')\nprint(agent._log)", "option_a": "['hello']", "option_b": "['HELLO', 'logged: hello']", "option_c": "['logged: hello']", "option_d": "['HELLO']", "correct_answer": "B", "difficulty": "advanced", "topic": "design_patterns"},
