    {"question_text": "What is the output of this implementation of the Interpreter pattern for a simple query DSL?\n\nclass Expression:\n    def interpret(self, context): pass\n\nclass NumberExpr(Expression):\n    def __init__(self, value): self.value = value\n    def interpret(self, context): return self.value\n\nclass AddExpr(Expression):\n    def __init__(self, left, right):\n        self.left = left\n        self.right = right\n    def interpret(self, context):\n        return self.left.interpret(context) + self.right.interpret(context)\n\nclass VarExpr(Expression):\n    def __init__(self, name): self.name = name\n    def interpret(self, context): return context[self.name]\n\nexpr = AddExpr(VarExpr('x'), NumberExpr(10))\nresult = expr.interpret({'x': 5})\nprint(result)", "option_a": "5", "option_b": "15", "option_c": "10", "option_d": "'x10'", "correct_answer": "B", "difficulty": "advanced", "topic": "design_patterns"},

    {"question_text": "What is the output of this implementation combining Strategy and Factory patterns?\n\nclass ProcessorFactory:\n    _processors = {}\n    \n    @classmethod\n    def register(cls, name):\n        def decorator(processor_cls):\n            cls._processors[name] = processor_cls\n            return processor_cls\n        return decorator\n    \n    @classmethod\n    def create(cls, name):\n        return cls._processors[name]()\n\n@ProcessorFactory.register('text')\nclass TextProcessor:\n    def process(self, data): return f'text: {data}'\n\n@ProcessorFactory.register('json')\nclass JSONProcessor:\n    def process(self, data): return f'json: {data}'\n\nprocessor = ProcessorFactory.create('json')\nprint(processor.process('hello'))", "option_a": "text: hello", "option_b": "json: hello", "option_c": "hello", "option_d": "KeyError", "correct_answer": "B", "difficulty": "advanced", "topic": "design_patterns"},
