    {"question_text": "What is the output of this Dependency Injection with a container?\n\nclass DIContainer:\n    def __init__(self):\n        self._factories = {}\n        self._singletons = {}\n    \n    def register_singleton(self, name, factory):\n        self._factories[name] = ('singleton', factory)\n    \n    def register_transient(self, name, factory):\n        self._factories[name] = ('transient', factory)\n    \n    def resolve(self, name):\n        lifetime, factory = self._factories[name]\n        if lifetime == 'singleton':\n            if name not in self._singletons:\n                self._singletons[name] = factory()\n            return self._singletons[name]\n        return factory()\n\ncontainer = DIContainer()\ncounter = [0]\ndef make_service():\n    counter[0] += 1\n    return f'service_{counter[0]}'\n\ncontainer.register_singleton('db', make_service)\na = container.resolve('db')\nb = container.resolve('db')\nprint(a == b, counter[0])", "option_a": "False 2", "option_b": "True 2", "option_c": "True 1", "option_d": "False 1", "correct_answer": "C", "difficulty": "advanced", "topic": "design_patterns"},
    {"question_text": "What is the output?\n\nclass StateMachine:\n    def __init__(self):\n        self._transitions = {}\n        self._current = None\n    \n    def add_transition(self, from_state, event, to_state, action=None):\n        self._transitions[(from_state, event)] = (to_state, action)\n    \n    def set_state(self, state):\n        self._current = state\n    \n    def trigger(self, event):\n        key = (self._current, event)\n        if key in self._transitions:\n            new_state, action = self._transitions[key]\n            if action:\n                action()\n            self._current = new_state\n            return True\n        return False\n\nsm = StateMachine()\nsm.add_transition('idle', 'start', 'running')\nsm.add_transition('running', 'stop', 'idle')\nsm.add_transition('running', 'error', 'failed')\nsm.set_state('idle')\nsm.trigger('start')\nsm.trigger('error')\nprint(sm._current)", "option_a": "idle", "option_b": "running", "option_c": "failed", "option_d": "error", "correct_answer": "C", "difficulty": "advanced", "topic": "design_patterns"},

