    {"question_text": "What is the output of this implementation of the Strategy pattern with a context class?\n\nfrom typing import Protocol\n\nclass Sorter(Protocol):\n    def sort(self, data: list) -> list: ...\n\nclass BubbleSort:\n    def sort(self, data):\n        arr = data.copy()\n        for i in range(len(arr)):\n            for j in range(len(arr)-1-i):\n                if arr[j] > arr[j+1]:\n                    arr[j], arr[j+1] = arr[j+1], arr[j]\n        return arr\n\nclass QuickSort:\n    def sort(self, data):\n        if len(data) <= 1: return data\n        pivot = data[0]\n        left = [x for x in data[1:] if x <= pivot]\n        right = [x for x in data[1:] if x > pivot]\n        return QuickSort().sort(left) + [pivot] + QuickSort().sort(right)\n\nclass SortContext:\n    def __init__(self, strategy):\n        self._strategy = strategy\n    def execute(self, data):\n        return self._strategy.sort(data)\n\nctx = SortContext(QuickSort())\nresult = ctx.execute([3, 1, 4, 1, 5])\nprint(result)", "option_a": "[5, 4, 3, 1, 1]", "option_b": "[3, 1, 4, 1, 5]", "option_c": "[1, 1, 3, 4, 5]", "option_d": "TypeError", "correct_answer": "C", "difficulty": "advanced", "topic": "design_patterns"},
    {"question_text": "What is the output of this Decorator pattern with multiple layers?\n\nclass BaseAgent:\n    def respond(self, query):\n        return f'answer to: {query}'\n\nclass LoggingAgent:\n    def __init__(self, agent):\n        self._agent = agent\n    def respond(self, query):\n        result = self._agent.respond(query)\n        return f'[LOG] {result}'\n\nclass CachingAgent:\n    def __init__(self, agent):\n        self._agent = agent\n        self._cache = {}\n    def respond(self, query):\n        if query not in self._cache:\n            self._cache[query] = self._agent.respond(query)\n        return self._cache[query]\n\nagent = CachingAgent(LoggingAgent(BaseAgent()))\nprint(agent.respond('hi'))", "option_a": "answer to: hi", "option_b": "[LOG] answer to: hi [LOG]", "option_c": "[LOG] answer to: hi", "option_d": "hi", "correct_answer": "C", "difficulty": "advanced", "topic": "design_patterns"},
    {"question_text": "What is the SOLID principle violated by this code?\n\nclass Shape:\n    def area(self): pass\n\nclass Rectangle(Shape):\n    def __init__(self, w, h): self.w = w; self.h = h\n    def area(self): return self.w * self.h\n\nclass Square(Rectangle):\n    def __init__(self, side):\n        super().__init__(side, side)\n    # Problem: setting w without h breaks the square invariant\n\nWhat happens if we allow square.w = 5 without updating h?", "option_a": "Single Responsibility is violated", "option_b": "Open/Closed is violated", "option_c": "Liskov Substitution is violated - Square cannot be substituted for Rectangle without breaking expectations", "option_d": "Interface Segregation is violated", "correct_answer": "C", "difficulty": "advanced", "topic": "design_patterns"},

    {"question_text": "What is the output?\n\nclass EventStore:\n    def __init__(self):\n        self.events = []\n        self.snapshots = {}\n    \n    def append(self, event):\n        self.events.append(event)\n    \n    def snapshot(self, name):\n        self.snapshots[name] = len(self.events)\n    \n    def events_since(self, name):\n        start = self.snapshots.get(name, 0)\n        return self.events[start:]\n\nstore = EventStore()\nstore.append('create')\nstore.append('update')\nstore.snapshot('v1')\nstore.append('delete')\nstore.append('create')\nresult = store.events_since('v1')\nprint(result)", "option_a": "['create', 'update']", "option_b": "['create', 'update', 'delete', 'create']", "option_c": "['delete', 'create']", "option_d": "['delete']", "correct_answer": "C", "difficulty": "advanced", "topic": "design_patterns"},
