    {"question_text": "What is the output of this implementation of the Retry pattern with different strategies?\n\nclass RetryStrategy:\n    def should_retry(self, attempt, exception): return False\n    def get_delay(self, attempt): return 0\n\nclass ExponentialBackoff(RetryStrategy):\n    def __init__(self, max_attempts=3, base_delay=1):\n        self.max_attempts = max_attempts\n        self.base_delay = base_delay\n    def should_retry(self, attempt, exception):\n        return attempt < self.max_attempts\n    def get_delay(self, attempt):\n        return self.base_delay * (2 ** attempt)\n\nstrategy = ExponentialBackoff(max_attempts=3, base_delay=1)\ndelays = [strategy.get_delay(i) for i in range(4)]\nprint(delays)", "option_a": "[0, 1, 2, 3]", "option_b": "[1, 1, 1, 1]", "option_c": "[1, 2, 4, 8]", "option_d": "[2, 4, 8, 16]", "correct_answer": "C", "difficulty": "advanced", "topic": "design_patterns"},
    {"question_text": "What anti-pattern is shown here and what pattern would fix it?\n\nclass Agent:\n    def process(self, task_type, data):\n        if task_type == 'search':\n            return self._search(data)\n        elif task_type == 'calculate':\n            return self._calculate(data)\n        elif task_type == 'translate':\n            return self._translate(data)\n        elif task_type == 'summarize':\n            return self._summarize(data)\n        # ... 20 more elif branches", "option_a": "Factory would fix this", "option_b": "Observer would fix this", "option_c": "Strategy or Command pattern would replace the conditional with polymorphism - register handlers by type", "option_d": "Singleton would fix this", "correct_answer": "C", "difficulty": "advanced", "topic": "design_patterns"},
    {"question_text": "What is the output of this implementation of a simple DI container using type annotations?\n\nclass Container:\n    def __init__(self):\n        self._bindings = {}\n    \n    def bind(self, interface, implementation):\n        self._bindings[interface] = implementation\n    \n    def resolve(self, cls):\n        if cls in self._bindings:\n            impl = self._bindings[cls]\n            return impl() if callable(impl) else impl\n        return cls()\n\nclass IDatabase:\n    pass\n\nclass SQLDatabase(IDatabase):\n    def query(self): return 'sql_result'\n\ncontainer = Container()\ncontainer.bind(IDatabase, SQLDatabase)\ndb = container.resolve(IDatabase)\nprint(db.query())", "option_a": "IDatabase", "option_b": "None", "option_c": "sql_result", "option_d": "TypeError", "correct_answer": "C", "difficulty": "advanced", "topic": "design_patterns"},
    {"question_text": "What is the output?\n\nclass Immutable:\n    def __init__(self, **kwargs):\n        for key, value in kwargs.items():\n            object.__setattr__(self, key, value)\n    \n    def __setattr__(self, key, value):\n        raise AttributeError('Cannot modify immutable object')\n    \n    def with_changes(self, **kwargs):\n        current = {k: v for k, v in self.__dict__.items()}\n        current.update(kwargs)\n        return Immutable(**current)\n\nconfig = Immutable(host='localhost', port=8080)\nnew_config = config.with_changes(port=9090)\nprint(config.port, new_config.port)", "option_a": "9090 9090", "option_b": "9090 8080", "option_c": "8080 9090", "option_d": "8080 8080", "correct_answer": "C", "difficulty": "advanced", "topic": "design_patterns"},
