    {"question_text": "What is the output?\n\nclass WeightedStrategy:\n    def __init__(self):\n        self._strategies = []\n    \n    def add(self, strategy, weight):\n        self._strategies.append((strategy, weight))\n    \n    def execute(self, data):\n        results = []\n        total_weight = sum(w for _, w in self._strategies)\n        for strategy, weight in self._strategies:\n            result = strategy(data)\n            results.append(result * weight / total_weight)\n        return sum(results)\n\nws = WeightedStrategy()\nws.add(lambda x: x * 2, 3)\nws.add(lambda x: x * 4, 1)\nresult = ws.execute(10)\nprint(result)", "option_a": "30.0", "option_b": "20.0", "option_c": "40.0", "option_d": "25.0", "correct_answer": "D", "difficulty": "advanced", "topic": "design_patterns"},
    {"question_text": "What is the output?\n\nclass StateContext:\n    def __init__(self, initial_state):\n        self._state = initial_state\n        self._transitions = 0\n    \n    def transition_to(self, state):\n        self._state = state\n        self._transitions += 1\n    \n    def request(self, action):\n        return self._state.handle(self, action)\n\nclass ActiveState:\n    def handle(self, context, action):\n        if action == 'deactivate':\n            context.transition_to(InactiveState())\n            return 'deactivated'\n        return 'processing'\n\nclass InactiveState:\n    def handle(self, context, action):\n        if action == 'activate':\n            context.transition_to(ActiveState())\n            return 'activated'\n        return 'dormant'\n\nctx = StateContext(ActiveState())\nctx.request('process')\nctx.request('deactivate')\nctx.request('activate')\nprint(ctx._transitions)", "option_a": "1", "option_b": "3", "option_c": "0", "option_d": "2", "correct_answer": "D", "difficulty": "advanced", "topic": "design_patterns"},

